import { Routes, Route, Navigate } from 'react-router-dom';
import { useSelector } from 'react-redux';
import Navbar from './components/Navbar';
import Login from './pages/Login';
import Register from './pages/Register';
import Dashboard from './pages/Dashboard';
import Courses from './pages/Courses';
import Admin from './pages/Admin';
import TakeTest from './pages/TakeTest';
import AddTest from './pages/AddTest';
import { ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';

function App() {
  const { user, isAuthenticated } = useSelector((state) => state.auth);

  const ProtectedRoute = ({ element, allowedRoles }) => {
    if (!isAuthenticated) {
      return <Navigate to="/login" />;
    }
    if (allowedRoles && !allowedRoles.includes(user?.role)) {
      return <Navigate to="/dashboard" />;
    }
    return element;
  };

  return (
    <div>
      <Navbar />
      <Routes>
        <Route path="/login" element={!isAuthenticated ? <Login /> : <Navigate to="/dashboard" />} />
        <Route path="/register" element={!isAuthenticated ? <Register /> : <Navigate to="/dashboard" />} />
        <Route path="/dashboard" element={<ProtectedRoute element={<Dashboard />} />} />
        <Route path="/courses" element={<ProtectedRoute element={<Courses />} allowedRoles={['student', 'teacher']} />} />
        <Route path="/admin" element={<ProtectedRoute element={<Admin />} allowedRoles={['admin']} />} />
        <Route path="/take-test/:testId" element={<ProtectedRoute element={<TakeTest />} allowedRoles={['student']} />} />
        <Route path="/add-test" element={<ProtectedRoute element={<AddTest />} allowedRoles={['teacher']} />} />
        <Route path="*" element={<Navigate to={isAuthenticated ? "/dashboard" : "/login"} />} />
      </Routes>
      <ToastContainer />
    </div>
  );
}

export default App;
